function tryRequireMany(paths) {
  for (const p of paths) {
    try {
      const mod = require(p);
      if (mod) return mod;
    } catch (_) {}
  }
  return null;
}

function tryRequireManyWithStatus(paths) {
  for (const p of Array.isArray(paths) ? paths : []) {
    try {
      const resolved = require.resolve(p);
      const mod = require(resolved);
      if (mod) {
        return {
          ok: true,
          mod,
          requested: p,
          resolvedPath: resolved,
          version: cleanText(mod.VERSION || "")
        };
      }
    } catch (err) {}
  }
  return { ok: false, mod: null, requested: "", resolvedPath: "", version: "" };
}

function moduleAvailable(name) {
  try {
    require.resolve(name);
    return true;
  } catch (_) {
    return false;
  }
}

const LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION = "nyx.lingosentinel.translationRouteMount/1.1-render-boot-safe-optional-require";
const LINGOSENTINEL_TRANSLATION_ROUTE_REQUIRE_CANDIDATES = Object.freeze([
  "./Data/marion/routes/lingosentinelTranslationRoutes",
  "./Data/marion/routes/lingosentinelTranslationRoutes.js",
  "./Data/marion/routes/LingoSentinelTranslationRoutes",
  "./Data/marion/routes/LingoSentinelTranslationRoutes.js",
  "./Data/marion/routes/lingoSentinelTranslationRoutes",
  "./Data/marion/routes/lingoSentinelTranslationRoutes.js"
]);

function loadLingoSentinelTranslationRouteModule() {
  let lastError = null;
  for (const candidate of LINGOSENTINEL_TRANSLATION_ROUTE_REQUIRE_CANDIDATES) {
    try {
      const mod = require(candidate);
      if (mod && typeof mod.registerLingoSentinelTranslationRoutes === "function") {
        return {
          ok: true,
          candidate,
          module: mod,
          version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION
        };
      }
      lastError = new Error(`candidate_missing_register_function:${candidate}`);
    } catch (err) {
      lastError = err;
    }
  }
  return {
    ok: false,
    candidate: "",
    module: null,
    version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION,
    error: lastError && (lastError.code || lastError.message || String(lastError)) || "module_unavailable"
  };
}

function mountLingoSentinelTranslationRoutesOptional(appInstance, label) {
  const mountLabel = String(label || "lingosentinel-translation-routes");
  const locals = appInstance && appInstance.locals ? appInstance.locals : null;
  if (locals && locals.__lingoSentinelTranslationRoutesMounted) {
    return {
      ok: true,
      mounted: false,
      alreadyMounted: true,
      degraded: false,
      label: mountLabel,
      version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION,
      previousMount: locals.__lingoSentinelTranslationRoutesMounted
    };
  }
  const loaded = loadLingoSentinelTranslationRouteModule();
  if (!loaded.ok || !loaded.module) {
    return {
      ok: false,
      mounted: false,
      degraded: true,
      label: mountLabel,
      version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION,
      reason: "optional_translation_route_module_unavailable",
      error: loaded.error || "module_unavailable"
    };
  }
  try {
    const mounted = loaded.module.registerLingoSentinelTranslationRoutes(appInstance);
    if (locals) {
      locals.__lingoSentinelTranslationRoutesMounted = {
        label: mountLabel,
        candidate: loaded.candidate,
        mountedAt: Date.now(),
        version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION
      };
    }
    return {
      ok: true,
      mounted: true,
      alreadyMounted: false,
      degraded: false,
      label: mountLabel,
      version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION,
      candidate: loaded.candidate,
      mount: mounted
    };
  } catch (err) {
    return {
      ok: false,
      mounted: false,
      degraded: true,
      label: mountLabel,
      version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION,
      candidate: loaded.candidate,
      reason: "translation_route_mount_failed",
      error: err && (err.code || err.message || String(err)) || "mount_failed"
    };
  }
}

function mountLingoSentinelTranslationRoutesOnce(appInstance, label) {
  const mountLabel = String(label || "lingosentinel-translation-routes");
  const locals = appInstance && appInstance.locals ? appInstance.locals : null;
  if (locals && locals.__lingoSentinelTranslationRoutesOnceResult) {
    return {
      ...locals.__lingoSentinelTranslationRoutesOnceResult,
      mounted: false,
      alreadyMounted: true,
      label: mountLabel,
      requestedLabel: mountLabel,
      previousMount: locals.__lingoSentinelTranslationRoutesOnceResult
    };
  }
  const result = mountLingoSentinelTranslationRoutesOptional(appInstance, mountLabel);
  if (locals) {
    locals.__lingoSentinelTranslationRoutesOnceResult = {
      ok: result && result.ok === true,
      mounted: result && result.mounted === true,
      degraded: result && result.degraded === true,
      label: mountLabel,
      candidate: result && result.candidate || "",
      reason: result && result.reason || "",
      error: result && result.error || "",
      version: LINGOSENTINEL_TRANSLATION_ROUTE_MOUNT_VERSION,
      attemptedAt: Date.now()
    };
  }
  return result;
}

