app.post(NYX_VOICE_TRANSCRIPT_ROUTES, async (req, res) => {
  hardenCors(req, res);
  hardenConversationNoStore(res);

  const startedAt = now();
  const body = isObj(req.body) ? req.body : {};
  const transcript = cleanText(body.transcript || body.text || body.message || body.query || "");
  const traceId = cleanText(req.headers["x-sb-trace-id"] || body.traceId || body.requestId || `voice_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`);
  const adminVoiceAuth = marionAdminVoiceRequestAuth(req, body);

  if (!transcript) {
    return res.status(400).json({
      ok: false,
      reply: "I did not receive a usable voice transcript.",
      text: "I did not receive a usable voice transcript.",
      message: "I did not receive a usable voice transcript.",
      publicAgent: "Nyx",
      authority: "Marion",
      inputChannel: "voice",
      source: "voice",
      error: "empty_voice_transcript",
      route: "/api/nyx/voice/transcript",
      version: NYX_VOICE_TRANSCRIPT_ROUTE_VERSION,
      adminOnlyVoiceDelivery: true,
      voice: {
        speakAllowed: false,
        voiceMode: "silent",
        reason: "EMPTY_TRANSCRIPT",
        spokenText: "",
        audioStored: false,
        adminOnlyVoiceDelivery: true,
        adminVoiceDeliveryAllowed: false
      },
      meta: { traceId, latencyMs: now() - startedAt, adminOnlyVoiceDeliveryVersion: MARION_ADMIN_ONLY_VOICE_DELIVERY_VERSION }
    });
  }

  let MarionVoiceGateway = null;
  try {
    MarionVoiceGateway = require("./Data/marion/runtime/MarionVoiceGateway.js");
  } catch (err) {
    MarionVoiceGateway = null;
  }

  if (!MarionVoiceGateway || typeof MarionVoiceGateway.handleVoiceTranscript !== "function") {
    return res.status(503).json({
      ok: false,
      reply: "Voice transcript routing is mounted, but the protected voice gateway is not available yet.",
      text: "Voice transcript routing is mounted, but the protected voice gateway is not available yet.",
      message: "Voice transcript routing is mounted, but the protected voice gateway is not available yet.",
      publicAgent: "Nyx",
      authority: "Marion",
      inputChannel: "voice",
      source: "voice",
      error: "marion_voice_gateway_unavailable",
      route: "/api/nyx/voice/transcript",
      version: NYX_VOICE_TRANSCRIPT_ROUTE_VERSION,
      deploymentParityVersion: NYX_VOICE_DEPLOYMENT_PARITY_VERSION,
      adminOnlyVoiceDelivery: true,
      voice: {
        speakAllowed: false,
        voiceMode: "silent",
        reason: "MARION_VOICE_GATEWAY_UNAVAILABLE",
        spokenText: "",
        audioStored: false,
        adminOnlyVoiceDelivery: true,
        adminVoiceDeliveryAllowed: false
      },
      runtimeFiles: nyxVoiceRequiredRuntimeDiagnostics(),
      runtimeFilesReady: nyxVoiceRuntimeFilesReady(),
      meta: {
        traceId,
        latencyMs: now() - startedAt,
        deploymentParityVersion: NYX_VOICE_DEPLOYMENT_PARITY_VERSION,
        readme: "README.md"
      }
    });
  }

  try {
    const packet = await MarionVoiceGateway.handleVoiceTranscript({
      transcript,
      confidence: body.confidence,
      locale: cleanText(body.locale || body.language || "en-CA"),
      provider: cleanText(body.provider || "browser-native"),
      speakerHint: adminVoiceAuth.verified ? cleanText(body.speakerHint || body.speaker || body.user || "") : "",
      claimedSpeaker: adminVoiceAuth.verified ? cleanText(body.claimedSpeaker || body.speaker || body.user || "") : "",
      detectedSpeakerId: adminVoiceAuth.verified ? cleanText(body.detectedSpeakerId || body.speakerId || "") : "",
      speakerConfidence: body.speakerConfidence,
      voiceMatchStatus: cleanText(body.voiceMatchStatus || ""),
      voiceProfileEnrolled: body.voiceProfileEnrolled === true,
      sessionRole: adminVoiceAuth.verified ? "owner" : "blocked",
      requestTrustedSpeakerHint: adminVoiceAuth.verified === true,
      sessionId: cleanText(body.sessionId || "public"),
      requestId: traceId,
      userAgent: cleanText(req.headers["user-agent"] || ""),
      client: cleanText(body.client || "web"),
      final: body.final !== false,
      interim: body.interim === true,
      adminOnlyVoiceDelivery: true,
      adminVoiceVerified: adminVoiceAuth.verified,
      adminVoiceTokenVerified: adminVoiceAuth.verified,
      adminVoiceAuthSource: adminVoiceAuth.verified ? adminVoiceAuth.source : ""
    }, {
      authorization: {
        adminOnlyVoiceDelivery: true,
        allowConversationalWhenUnknown: false,
        trustSpeakerHint: adminVoiceAuth.verified,
        adminVoiceVerified: adminVoiceAuth.verified,
        adminVoiceTokenVerified: adminVoiceAuth.verified,
        adminVoiceDeliveryAllowed: adminVoiceAuth.verified
      },
      output: {
        adminOnlyVoiceDelivery: true,
        adminVoiceVerified: adminVoiceAuth.verified,
        adminVoiceTokenVerified: adminVoiceAuth.verified,
        adminVoiceDeliveryAllowed: adminVoiceAuth.verified,
        forceSilent: !adminVoiceAuth.verified
      },
      context: {
        sessionId: cleanText(body.sessionId || "public"),
        requestId: traceId,
        inputChannel: "voice",
        source: "voice",
        publicAgent: "Nyx",
        authority: "Marion",
        adminOnlyVoiceDelivery: true,
        adminVoiceVerified: adminVoiceAuth.verified,
        adminVoiceDeliveryAllowed: adminVoiceAuth.verified
      }
    });

    const voice = isObj(packet && packet.voice) ? packet.voice : {};
    const voiceEnvelope = isObj(packet && packet.voiceEnvelope) ? packet.voiceEnvelope : {};
    const adminVoiceDeliveryAllowed = adminVoiceAuth.verified === true && (
      voice.adminVoiceDeliveryAllowed === true ||
      voiceEnvelope.adminVoiceDeliveryAllowed === true ||
      cleanText(voiceEnvelope.authorizationState || "") === "authorized"
    );
    const rawPromotedReply = nyxVoiceRouteReplyText(packet) || nyxVoiceRouteReplyText(voice);
    const allowProtectedStatusFinal = adminVoiceDeliveryAllowed &&
      (voice.finalApproved === true || voice.finalEnvelopeOnly === true || voice.protectedStatusIntent === true) &&
      nyxVoiceRouteIsProtectedStatusReply(rawPromotedReply);
    const promotedReply = nyxVoiceRouteIsInputEchoReply(rawPromotedReply, packet, body, { allowProtectedStatusFinal }) ? "" : rawPromotedReply;
    const reply = nyxVoiceRouteEnsureNonEmptyReply(promotedReply, packet, body);
    const promotedSafe = nyxVoiceRouteSafePublicReply(promotedReply);
    const rawSpokenCandidate = cleanText(voice.spokenText || ((voice.speakAllowed === true || allowProtectedStatusFinal) ? (promotedSafe || reply) : ""));
    const spokenCandidateEchoSuppressed = nyxVoiceRouteIsInputEchoReply(rawSpokenCandidate, packet, body, {
      allowProtectedStatusFinal: allowProtectedStatusFinal || (adminVoiceDeliveryAllowed && nyxVoiceRouteIsProtectedStatusReply(rawSpokenCandidate))
    });
    const promotedEchoSuppressed = Boolean(rawPromotedReply && !promotedReply);
    const voiceEchoSuppressed = promotedEchoSuppressed || spokenCandidateEchoSuppressed;
    const voiceReplyPromotionFallback = (!promotedSafe && Boolean(reply)) || voiceEchoSuppressed || voice.replyPromotionFallback === true;
    const routeSpeakAllowed = adminVoiceDeliveryAllowed &&
      (voice.speakAllowed === true || allowProtectedStatusFinal) &&
      !voiceEchoSuppressed &&
      Boolean(rawSpokenCandidate || promotedSafe || reply);
    const spokenCandidate = routeSpeakAllowed ? (rawSpokenCandidate || promotedSafe || reply) : "";
    const spokenText = routeSpeakAllowed ? (nyxVoiceRouteSafePublicReply(spokenCandidate) || reply) : "";
    const projectedVoiceMode = nyxVoiceRouteProjectedVoiceMode(voice.voiceMode, routeSpeakAllowed, spokenText);
    const rawVoiceMode = cleanText(voice.voiceMode || "");
    const voiceSpeechSync = isObj(voice.speechSync) ? voice.speechSync : {};
    const speechSync = routeSpeakAllowed && isObj(voiceSpeechSync) && voiceSpeechSync.enabled === true
      ? voiceSpeechSync
      : {
        enabled: false,
        reason: routeSpeakAllowed ? "SPEECH_SYNC_NOT_SUPPLIED_BY_GATEWAY" : "VOICE_NOT_SPEAKABLE",
        audioStored: false,
        transcriptOnly: true
      };

    return res.status(packet && packet.ok === false ? 202 : 200).json({
      ok: !(packet && packet.ok === false),
      final: true,
      handled: true,
      reply,
      text: reply,
      message: reply,
      displayReply: reply,
      publicAgent: "Nyx",
      authority: "Marion",
      inputChannel: "voice",
      source: "voice",
      route: "/api/nyx/voice/transcript",
      version: NYX_VOICE_TRANSCRIPT_ROUTE_VERSION,
      voice: {
        speakAllowed: routeSpeakAllowed,
        voiceMode: projectedVoiceMode,
        rawVoiceMode,
        voiceModeProjectionHardlock: true,
        voiceModeProjected: routeSpeakAllowed && !!spokenText && projectedVoiceMode !== "silent" && rawVoiceMode.toLowerCase() !== projectedVoiceMode,
        reason: !adminVoiceDeliveryAllowed ? "ADMIN_ONLY_VOICE_DELIVERY_REQUIRED" : voiceEchoSuppressed ? "VOICE_ROUTE_ECHO_SUPPRESSED_FALLBACK" : (routeSpeakAllowed && allowProtectedStatusFinal && voice.speakAllowed !== true) ? "VOICE_ROUTE_PROTECTED_STATUS_FINAL_APPROVED" : voiceReplyPromotionFallback ? "VOICE_ROUTE_REPLY_PROMOTION_FALLBACK" : cleanText(voice.reason || ""),
        spokenText,
        audioStored: false,
        adminOnlyVoiceDelivery: true,
        adminVoiceDeliveryAllowed,
        replyPromotionFallback: voice.replyPromotionFallback === true || voiceReplyPromotionFallback,
        echoSuppressed: voiceEchoSuppressed,
        nonEmptyReplyHardlock: true,
        finalEnvelopeOnly: voice.finalEnvelopeOnly === true || allowProtectedStatusFinal,
        finalApproved: voice.finalApproved === true || allowProtectedStatusFinal,
        protectedStatusIntent: voice.protectedStatusIntent === true,
        protectedStatusFinalAllowed: allowProtectedStatusFinal,
        duplicateSuppressed: voice.duplicateSuppressed === true,
        stabilizerVersion: cleanText(voice.stabilizerVersion || ""),
        ttsFallbackSafe: voice.ttsFallbackSafe !== false,
        textFallbackAvailable: voice.textFallbackAvailable !== false,
        speechSync,
        speechSyncEnabled: speechSync.enabled === true,
        speechSyncVersion: cleanText(speechSync.version || voice.speechSyncVersion || ""),
        avatarSpeechState: cleanText(speechSync.avatarSpeechState || speechSync.speechState || ""),
        phase2SpeechSyncPrepared: speechSync.enabled === true
      },
      voiceEnvelope: {
        source: "voice",
        inputChannel: "voice",
        locale: cleanText(voiceEnvelope.locale || body.locale || "en-CA"),
        confidence: Number.isFinite(Number(voiceEnvelope.confidence)) ? Number(voiceEnvelope.confidence) : null,
        authorizationState: cleanText(voiceEnvelope.authorizationState || ""),
        adminOnlyVoiceDelivery: true,
        adminVoiceVerified: adminVoiceAuth.verified === true,
        adminVoiceDeliveryAllowed,
        userIntentHint: cleanText(voiceEnvelope.userIntentHint || ""),
        commandPhrase: cleanText(voiceEnvelope.commandPhrase || ""),
        wakeWord: cleanText(voiceEnvelope.wakeWord || ""),
        audioStored: false
      },
      meta: {
        traceId,
        latencyMs: now() - startedAt,
        routeAuthority: "Nyx public route -> MarionVoiceGateway -> MarionBridge",
        noRawAudioStored: true,
        voiceReplyPromotionFallback,
        voiceEchoSuppressed,
        adminOnlyVoiceDelivery: true,
        adminVoiceTokenConfigured: adminVoiceAuth.configured === true,
        adminVoiceTokenProvided: adminVoiceAuth.provided === true,
        adminVoiceDeliveryAllowed,
        adminOnlyVoiceDeliveryVersion: MARION_ADMIN_ONLY_VOICE_DELIVERY_VERSION,
        nonEmptyReplyHardlock: true,
        finalEnvelopeOnly: voice.finalEnvelopeOnly === true || allowProtectedStatusFinal,
        finalApproved: voice.finalApproved === true || allowProtectedStatusFinal,
        protectedStatusIntent: voice.protectedStatusIntent === true,
        protectedStatusFinalAllowed: allowProtectedStatusFinal,
        duplicateSuppressed: voice.duplicateSuppressed === true,
        stabilizerVersion: cleanText(voice.stabilizerVersion || ""),
        projectedVoiceMode,
        rawVoiceMode,
        voiceModeProjectionHardlock: true,
        speechSyncEnabled: speechSync.enabled === true,
        speechSyncVersion: cleanText(speechSync.version || voice.speechSyncVersion || ""),
        avatarSpeechState: cleanText(speechSync.avatarSpeechState || speechSync.speechState || ""),
        phase2SpeechSyncPrepared: speechSync.enabled === true,
        promotionHardlockVersion: "nyx.voiceReplyPromotionHardlock/1.7-phase2-speech-sync",
        deploymentParityVersion: NYX_VOICE_DEPLOYMENT_PARITY_VERSION,
        readme: "README.md",
        renderDeployParityRequired: true
      }
    });
  } catch (err) {
    const message = cleanText(err && (err.message || err) || "voice_transcript_route_failed");
    return res.status(500).json({
      ok: false,
      reply: "Voice transcript routing failed before Marion could finish the turn.",
      text: "Voice transcript routing failed before Marion could finish the turn.",
      message: "Voice transcript routing failed before Marion could finish the turn.",
      publicAgent: "Nyx",
      authority: "Marion",
      inputChannel: "voice",
      source: "voice",
      error: "voice_transcript_route_failed",
      detail: message.slice(0, 160),
      route: "/api/nyx/voice/transcript",
      version: NYX_VOICE_TRANSCRIPT_ROUTE_VERSION,
      deploymentParityVersion: NYX_VOICE_DEPLOYMENT_PARITY_VERSION,
      adminOnlyVoiceDelivery: true,
      voice: {
        speakAllowed: false,
        voiceMode: "silent",
        reason: "VOICE_TRANSCRIPT_ROUTE_FAILED",
        spokenText: "",
        audioStored: false,
        adminOnlyVoiceDelivery: true,
        adminVoiceDeliveryAllowed: false
      },
      meta: {
        traceId,
        latencyMs: now() - startedAt,
        deploymentParityVersion: NYX_VOICE_DEPLOYMENT_PARITY_VERSION,
        readme: "README.md"
      }
    });
  }
});

