          marionIntent: isObj(routed.marionIntent) ? routed.marionIntent : normalized,
          routing: isObj(routed.routing) ? routed.routing : buildMarionIntentRouting(normalized, lane),
          meta: isObj(routed.meta) ? routed.meta : {}
