function getNyxTtsRuntimeConfigStatus() {
  const token = nyxTtsResolveEnvAlias(NYX_TTS_ENV_ALIASES.token);
  const voice = nyxTtsResolveEnvAlias(NYX_TTS_ENV_ALIASES.voice);
  const synthUrl = nyxTtsNormalizeEndpoint(process.env.RESEMBLE_SYNTH_URL, NYX_TTS_DEFAULT_SYNTH_URL);
  const streamUrl = nyxTtsNormalizeEndpoint(process.env.RESEMBLE_STREAM_URL, NYX_TTS_DEFAULT_STREAM_URL);
  const missing = [];
  if (!token.configured) missing.push("token");
  if (!voice.configured) missing.push("voice");
  return {
    version: NYX_TTS_CONFIG_BRIDGE_VERSION,
    ready: missing.length === 0,
    tokenConfigured: token.configured,
    voiceConfigured: voice.configured,
    synthEndpointConfigured: !!synthUrl,
    streamEndpointConfigured: !!streamUrl,
    transportMode: nyxTtsCleanEnvValue(process.env.SB_TTS_TRANSPORT || "compat-first") || "compat-first",
    moduleLoaded: !!ttsHandlerFromModule(ttsMod),
    modulePath: ttsLoadStatus && ttsLoadStatus.requested || "",
    missing
  };
}

function applyNyxTtsDiagnosticHeaders(res, status) {
  const cfg = status && typeof status === "object" ? status : getNyxTtsRuntimeConfigStatus();
  try {
    res.setHeader("X-SB-TTS-Index-Bridge", NYX_TTS_CONFIG_BRIDGE_VERSION);
    res.setHeader("X-SB-TTS-Config-Ready", cfg.ready ? "1" : "0");
    res.setHeader("X-SB-TTS-Token-Configured", cfg.tokenConfigured ? "1" : "0");
    res.setHeader("X-SB-TTS-Voice-Configured", cfg.voiceConfigured ? "1" : "0");
    res.setHeader("X-SB-TTS-Module-Loaded", cfg.moduleLoaded ? "1" : "0");
    res.setHeader("X-SB-TTS-Transport", cfg.transportMode || "compat-first");
  } catch (_) {}
  return cfg;
}

function normalizePublicTtsRequest(req) {
  if (!req || typeof req !== "object") return req;
  const query = req.query && typeof req.query === "object" ? req.query : {};
  const body = req.body && typeof req.body === "object" && !Array.isArray(req.body) ? req.body : {};
  const method = String(req.method || "GET").toUpperCase();
  if (method === "GET") {
    const text = nyxTtsCleanEnvValue(query.text || query.data || query.message || query.speak || "");
    const outputFormat = nyxTtsCleanEnvValue(query.output_format || query.outputFormat || query.format || "").toLowerCase();
    req.body = {
      ...body,
      ...(text ? { text, data: text } : {}),
      ...(outputFormat === "wav" || outputFormat === "mp3" ? { output_format: outputFormat, outputFormat } : {}),
      ...(query.returnJson !== undefined ? { returnJson: query.returnJson } : {}),
      ...(query.json !== undefined ? { json: query.json } : {})
    };
  }
  return req;
}

function sendTtsJsonError(req, res, statusCode, error, detail, extra) {
  const code = clamp(Number(statusCode || 503), 400, 599);
  const traceId = cleanText((req && (req.sbTraceId || (req.headers && req.headers["x-sb-trace-id"]))) || makeTraceId("tts"));
  const safeExtra = isObj(extra) ? extra : {};
  const runtimeConfig = applyNyxTtsDiagnosticHeaders(res);
  try {
    res.setHeader("X-SB-Response-Mode", "error");
    res.setHeader("X-Content-Type-Options", "nosniff");
    res.setHeader("Content-Type", "application/json; charset=utf-8");
  } catch (_) {}
  const payload = {
    ok: false,
    playable: false,
    shouldPlay: false,
    autoPlay: false,
    spokenUnavailable: true,
    error: cleanText(error || "tts_route_failure") || "tts_route_failure",
    reason: cleanText(error || "tts_route_failure") || "tts_route_failure",
    detail: cleanText(detail || "TTS route failed") || "TTS route failed",
    retryable: safeExtra.retryable === true,
    provider: cleanText(safeExtra.provider || "resemble") || "resemble",
    providerStatus: Number(safeExtra.providerStatus || code) || code,
    traceId,
    diagnosticsRedacted: true,
    configSource: cleanText(safeExtra.configSource || ""),
    ttsModuleBound: safeExtra.ttsModuleBound === true,
    ttsIndexBridgeVersion: NYX_TTS_CONFIG_BRIDGE_VERSION,
    config: {
      ready: runtimeConfig.ready,
      tokenConfigured: runtimeConfig.tokenConfigured,
      voiceConfigured: runtimeConfig.voiceConfigured,
      synthEndpointConfigured: runtimeConfig.synthEndpointConfigured,
      streamEndpointConfigured: runtimeConfig.streamEndpointConfigured,
      moduleLoaded: runtimeConfig.moduleLoaded,
      missing: runtimeConfig.missing
    },
    payload: { spokenUnavailable: true, playable: false, shouldPlay: false, autoPlay: false },
    meta: { v: PUBLIC_INDEX_VERSION, t: now(), audioContract: "audio-first-v2" }
  };
  return res.status(code).json(payload);
}

function firstTruthyString() {
  for (const v of arguments) {
    const s = cleanText(v);
    if (s) return s;
  }
  return "";
}

function boolish(v, fallback) {
  if (v === true || v === false) return v;
  const s = lower(v);
  if (["1","true","yes","on"].includes(s)) return true;
  if (["0","false","no","off"].includes(s)) return false;
  return !!fallback;
}

function inferAudioMimeType(raw) {
  const direct = firstTruthyString(
    raw && raw.mimeType,
    raw && raw.contentType,
    raw && raw.audioMimeType,
    raw && raw.audio && raw.audio.mimeType,
    raw && raw.audio && raw.audio.contentType,
    raw && raw.payload && raw.payload.mimeType,
    raw && raw.payload && raw.payload.contentType
  );
  if (direct) return direct;
  const format = lower(
    firstTruthyString(
      raw && raw.format,
      raw && raw.audioFormat,
      raw && raw.audio && raw.audio.format,
      raw && raw.payload && raw.payload.format
    )
  );
  if (format === "mp3" || format === "mpeg") return "audio/mpeg";
  if (format === "wav" || format === "wave") return "audio/wav";
  if (format === "ogg") return "audio/ogg";
  if (format === "webm") return "audio/webm";
  if (format === "mp4" || format === "m4a") return "audio/mp4";
  return "audio/mpeg";
}

function detectTtsBinaryMime(buffer) {
  if (!Buffer.isBuffer(buffer) || !buffer.length) return "";
  if (buffer.length >= 12 && buffer.slice(0, 4).toString("ascii") === "RIFF" && buffer.slice(8, 12).toString("ascii") === "WAVE") return "audio/wav";
  if (buffer.length >= 4 && buffer.slice(0, 4).toString("ascii") === "OggS") return "audio/ogg";
  if (buffer.length >= 4 && buffer.slice(0, 4).toString("ascii") === "fLaC") return "audio/flac";
  if (buffer.length >= 3 && buffer.slice(0, 3).toString("ascii") === "ID3") return "audio/mpeg";
  for (let index = 0; index < Math.min(buffer.length - 1, 64); index += 1) {
    if (buffer[index] === 0xff && (buffer[index + 1] & 0xe0) === 0xe0) return "audio/mpeg";
  }
  return "";
}

function looksLikeBase64Audio(v) {
  const s = cleanText(v);
  if (!s) return false;
  if (/^data:audio\//i.test(s)) return false;
  return s.length > 64 && /^[A-Za-z0-9+/=\s]+$/.test(s);
}

function normalizeTtsRoutePayload(raw, req) {
  const src = isObj(raw) ? raw : {};
  const payload = isObj(src.payload) ? src.payload : {};
  const audio = isObj(src.audio) && !Buffer.isBuffer(src.audio) ? src.audio : {};
  const speech = isObj(src.speech) ? src.speech : {};
  const result = isObj(src.result) ? src.result : {};
  const response = isObj(src.response) ? src.response : {};
  const dataObj = isObj(src.data) && !Buffer.isBuffer(src.data) ? src.data : {};
  const traceId = cleanText((req && (req.sbTraceId || (req.headers && req.headers["x-sb-trace-id"]))) || src.traceId || payload.traceId || makeTraceId("tts"));
  const containers = [src, payload, audio, result, response, dataObj];

  function safeAudioUrl(value) {
    const rawUrl = cleanText(value);
    if (!rawUrl) return "";
    try {
      const url = new URL(rawUrl);
      if (url.protocol === "https:") return url.toString();
      if (url.protocol === "http:" && ["localhost", "127.0.0.1", "::1"].includes(url.hostname)) return url.toString();
    } catch (_) {}
    return "";
  }

  function detectBufferMime(buffer) {
    if (!Buffer.isBuffer(buffer) || !buffer.length) return "";
    if (buffer.length >= 12 && buffer.slice(0, 4).toString("ascii") === "RIFF" && buffer.slice(8, 12).toString("ascii") === "WAVE") return "audio/wav";
    if (buffer.length >= 4 && buffer.slice(0, 4).toString("ascii") === "OggS") return "audio/ogg";
    if (buffer.length >= 4 && buffer.slice(0, 4).toString("ascii") === "fLaC") return "audio/flac";
    if (buffer.length >= 4 && buffer[0] === 0x1a && buffer[1] === 0x45 && buffer[2] === 0xdf && buffer[3] === 0xa3) return "audio/webm";
    if (buffer.length >= 12 && buffer.slice(4, 8).toString("ascii") === "ftyp") return "audio/mp4";
    if (buffer.length >= 3 && buffer.slice(0, 3).toString("ascii") === "ID3") return "audio/mpeg";
    for (let n = 0; n < Math.min(buffer.length - 1, 64); n += 1) if (buffer[n] === 0xff && (buffer[n + 1] & 0xe0) === 0xe0) return "audio/mpeg";
    return "";
  }

  function decodeAudioBase64(value, declaredMime) {
    let rawValue = cleanText(value);
    if (!rawValue) return null;
    let dataMime = "";
    const dataUri = /^data:(audio\/[^;]+);base64,(.+)$/i.exec(rawValue);
    if (dataUri) {
      dataMime = cleanText(dataUri[1]);
      rawValue = cleanText(dataUri[2]);
    }
    rawValue = rawValue.replace(/\s+/g, "");
    const maxBytes = clamp(Number(process.env.SB_TTS_MAX_AUDIO_BYTES || 25 * 1024 * 1024), 256 * 1024, 100 * 1024 * 1024);
    const maxBase64Chars = Math.ceil(maxBytes * 4 / 3) + 8;
    if (rawValue.length < 16 || rawValue.length > maxBase64Chars || !/^[A-Za-z0-9+/]+={0,2}$/.test(rawValue)) return null;
    try {
      const padded = rawValue + "=".repeat((4 - (rawValue.length % 4)) % 4);
      const buffer = Buffer.from(padded, "base64");
      if (!buffer.length || buffer.length > maxBytes) return null;
      const preview = buffer.slice(0, Math.min(buffer.length, 128)).toString("utf8").replace(/^\uFEFF/, "").trim().toLowerCase();
      if (preview.startsWith("{") || preview.startsWith("[") || preview.startsWith("<!doctype") || preview.startsWith("<html") || preview.startsWith("<body")) return null;
      const signatureMime = detectBufferMime(buffer);
      const requestedMime = cleanText(dataMime || declaredMime);
      if (!signatureMime && (!/^audio\//i.test(requestedMime) || buffer.length < 256)) return null;
      return { base64: buffer.toString("base64"), mimeType: signatureMime || requestedMime || "audio/mpeg", bytes: buffer.length };
    } catch (_) {
      return null;
    }
  }

  let audioUrl = "";
  for (const container of containers) {
    audioUrl = safeAudioUrl(firstTruthyString(container.audioUrl, container.audio_url, container.url, container.src, container.audioSrc, container.audio_src));
    if (audioUrl) break;
  }

  const declaredMime = inferAudioMimeType({ ...src, payload, audio });
  let decodedAudio = null;
  for (const container of containers) {
    const candidates = [container.audioBase64, container.audio_base64, container.audio_content, container.audioContent, container.base64, container.content, container.audioData];
    for (const candidate of candidates) {
      decodedAudio = decodeAudioBase64(candidate, declaredMime);
      if (decodedAudio) break;
    }
    if (decodedAudio) break;
  }

  const audioBase64 = decodedAudio ? decodedAudio.base64 : "";
  const playable = !!(audioUrl || audioBase64);
  const mimeType = playable ? (decodedAudio && decodedAudio.mimeType || declaredMime || "audio/mpeg") : "application/json";
  const text = repairCommonMojibake(cleanReplyForUser(firstTruthyString(
    src.text, src.textSpeak, src.textDisplay, src.spokenText,
    speech.textSpeak, speech.text, payload.textSpeak, payload.textDisplay, payload.spokenText, payload.text
  )));
  const format = playable ? (cleanText(firstTruthyString(src.format, src.audioFormat, audio.format, payload.format)) || (mimeType === "audio/mpeg" ? "mp3" : mimeType.replace(/^audio\//i, ""))) : "";
  const requestedAutoPlay = boolish(
    src.autoPlay !== undefined ? src.autoPlay :
    audio.autoPlay !== undefined ? audio.autoPlay :
    payload.autoPlay !== undefined ? payload.autoPlay :
    src.shouldPlay !== undefined ? src.shouldPlay :
    audio.shouldPlay !== undefined ? audio.shouldPlay :
    payload.shouldPlay !== undefined ? payload.shouldPlay :
    false,
    false
  );
  const autoPlay = !!(playable && requestedAutoPlay);
  const responseText = playable ? text : "";
  const error = firstTruthyString(...containers.map((container) => firstTruthyString(container.error, container.reason, container.code)));
  const detail = firstTruthyString(...containers.map((container) => firstTruthyString(container.detail, container.message)));
  const statusCandidate = Number(firstTruthyString(...containers.map((container) => firstTruthyString(container.providerStatus, container.upstreamStatus, container.status))));
  const providerStatus = Number.isFinite(statusCandidate) && statusCandidate > 0 ? statusCandidate : (playable ? 200 : 503);
  const retryable = boolish(firstTruthyString(...containers.map((container) => container.retryable)), false);
  const provider = firstTruthyString(...containers.map((container) => container.provider), process.env.TTS_PROVIDER || "resemble") || "resemble";

  if (!playable) {
    const compactError = error || "tts_audio_unavailable";
    return {
      ok: false,
      playable: false,
      autoPlay: false,
      shouldPlay: false,
      spokenUnavailable: true,
      error: compactError,
      reason: compactError,
      detail: detail || "No verified playable audio was returned.",
      retryable,
      provider,
      providerStatus,
      traceId,
      transport: firstTruthyString(...containers.map((container) => container.transport)) || getNyxTtsRuntimeConfigStatus().transportMode || "unknown",
      ttsVersion: firstTruthyString(...containers.map((container) => container.ttsVersion || container.version)) || NYX_TTS_CONFIG_BRIDGE_VERSION,
      ttsIndexBridgeVersion: NYX_TTS_CONFIG_BRIDGE_VERSION,
      config: (() => {
        const cfg = getNyxTtsRuntimeConfigStatus();
        return {
          ready: cfg.ready,
          tokenConfigured: cfg.tokenConfigured,
          voiceConfigured: cfg.voiceConfigured,
          synthEndpointConfigured: cfg.synthEndpointConfigured,
          streamEndpointConfigured: cfg.streamEndpointConfigured,
          moduleLoaded: cfg.moduleLoaded,
          missing: cfg.missing
        };
      })(),
      diagnosticsRedacted: true,
      audio: {
        ok: false,
        playable: false,
        audioUrl: "",
        audioBase64: "",
        byteLength: 0,
        mimeType: "application/json",
        contentType: "application/json",
        format: "",
        autoPlay: false,
        shouldPlay: false,
        provider
      },
      meta: {
        route: cleanText(req && (req.originalUrl || req.path) || "/api/tts") || "/api/tts",
        audioContract: "audio-first-v2",
        diagnosticsRedacted: true,
        t: now()
      }
    };
  }

  const normalizedAudio = {
    ok: playable,
    playable,
    url: audioUrl,
    src: audioUrl,
    audioUrl,
    audioBase64,
    byteLength: decodedAudio ? decodedAudio.bytes : 0,
    mimeType,
    contentType: mimeType,
    format,
    autoPlay,
    shouldPlay: autoPlay,
    provider,
    text: responseText,
    textSpeak: responseText,
    chars: responseText.length
  };

  return {
    ok: playable && src.ok !== false && !error,
    playable,
    autoPlay,
    shouldPlay: autoPlay,
    spokenUnavailable: !playable,
    error: error || (playable ? "" : "tts_audio_unavailable"),
    reason: error || (playable ? "" : "tts_audio_unavailable"),
    detail: detail || (playable ? "" : "No verified playable audio was returned."),
    retryable,
    provider,
    providerStatus,
    traceId,
    diagnosticsRedacted: true,
    audio: normalizedAudio,
    audioUrl,
    audioBase64,
    src: audioUrl,
    url: audioUrl,
    mimeType,
    contentType: mimeType,
    format,
    text: responseText,
    textSpeak: responseText,
    spokenText: responseText,
    speech: {
      enabled: playable,
      speak: playable,
      text: responseText,
      textDisplay: responseText,
      textSpeak: responseText,
      alignmentVersion: "speech-contract-v3"
    },
    payload: {
      playable,
      spokenUnavailable: !playable,
      audioUrl,
      audioBase64,
      byteLength: decodedAudio ? decodedAudio.bytes : 0,
      mimeType,
      format,
      autoPlay,
      shouldPlay: autoPlay,
      textSpeak: responseText,
      spokenText: responseText
    },
    meta: {
      v: PUBLIC_INDEX_VERSION,
      t: now(),
      route: cleanText(req && (req.originalUrl || req.path) || "/api/tts") || "/api/tts",
      audioContract: "audio-first-v2",
      diagnosticsRedacted: true
    }
  };
}

function sendRawTtsJson(res, status, body) {
  if (!res || res.writableEnded) return;
  const code = Number(status);
  res.statusCode = Number.isFinite(code) && code >= 100 && code <= 599 ? code : 500;
  try {
    res.setHeader("Content-Type", "application/json; charset=utf-8");
    res.setHeader("X-Content-Type-Options", "nosniff");
    res.setHeader("Cache-Control", "no-store, max-age=0");
  } catch (_) {}
  const json = JSON.stringify(body && typeof body === "object" ? body : { ok: false, error: "tts_invalid_response" });
  return res.end(json);
}

async function dispatchTts(req, res) {
  normalizePublicTtsRequest(req);
  req.sbTtsRoute = true;
  res.locals = res.locals || {};
  res.locals.sbTtsRoute = true;
  hardenConversationNoStore(res);
  const runtimeConfig = applyNyxTtsDiagnosticHeaders(res);
  try {
    res.setHeader("Vary", "Origin, Accept");
    res.setHeader("X-SB-Audio-Contract", "audio-first-v2");
    res.setHeader("X-SB-TTS-Response-Mode", "binary-audio-default");
    res.setHeader("X-Content-Type-Options", "nosniff");
  } catch (_) {}
  if (!runtimeConfig.ready) {
    return sendTtsJsonError(req, res, 503, "TTS_NOT_CONFIGURED", "TTS not configured in the running process.", {
      provider: "resemble",
      providerStatus: 503,
      retryable: false,
      configSource: "index_tts_env_bridge",
      ttsModuleBound: !!ttsHandlerFromModule(ttsMod)
    });
  }
  const moduleHandler = ttsHandlerFromModule(ttsMod);
  if (CFG.httpLogEnabled) {
    console.log("[Sandblast][ttsRoute:dispatch]", { path: req.originalUrl || req.path || "/api/tts", hasHandler: !!moduleHandler, host: getBackendPublicBase(), traceId: cleanText(req.sbTraceId || req.headers["x-sb-trace-id"] || "") });
  }
  if (!moduleHandler) throw new Error("tts_handler_unavailable");

  res.json = function patchedTtsJson(body) {
    const normalized = normalizeTtsRoutePayload(body, req);
    if (!normalized.playable) {
      try { res.setHeader("X-SB-Response-Mode", "error"); } catch (_) {}
    }
    return sendRawTtsJson(res, res.statusCode || (normalized.playable ? 200 : normalized.providerStatus || 503), normalized);
  };

  const result = await moduleHandler(req, res);
  if (res.headersSent || res.writableEnded) return result;

  if (Buffer.isBuffer(result) || result instanceof Uint8Array) {
    const buffer = Buffer.from(result);
    if (!buffer.length) return sendTtsJsonError(req, res, 502, "tts_empty_audio", "TTS returned an empty audio buffer.", { providerStatus: 502, retryable: true });
    try {
      const binaryMime = detectTtsBinaryMime(buffer);
      if (!binaryMime) return sendTtsJsonError(req, res, 502, "tts_invalid_binary_audio", "TTS returned bytes without a recognized audio signature.", { providerStatus: 502, retryable: true });
      res.status(200);
      res.setHeader("Content-Type", binaryMime);
      res.setHeader("Content-Length", String(buffer.length));
      res.setHeader("X-SB-Response-Mode", "audio");
      return res.end(buffer);
    } catch (_) {
      return sendTtsJsonError(req, res, 502, "tts_audio_send_failed", "TTS audio could not be sent.", { providerStatus: 502, retryable: true });
    }
  }

  if (result !== undefined) {
    const normalized = normalizeTtsRoutePayload(result, req);
    if (normalized.playable && normalized.ok) return sendRawTtsJson(res, 200, normalized);
    const rawStatus = Number(isObj(result) && (result.status || result.providerStatus) || normalized.providerStatus || 503);
    const status = rawStatus >= 400 && rawStatus < 600 ? rawStatus : 502;
    return sendRawTtsJson(res, status, normalized);
  }

  return sendTtsJsonError(req, res, 503, "tts_empty_response", "TTS handler completed without audio payload.", {
    configSource: "tts_module",
    ttsModuleBound: true,
    retryable: true,
    providerStatus: 503
  });
}

function attachVoiceRoute(base) {
  const shaped = isObj(base) ? { ...base } : {};
  const existing = isObj(shaped.voiceRoute) ? shaped.voiceRoute : {};
  const routeEnabled = !!CFG.voiceRouteEnabled;
  const route = {
    enabled: routeEnabled,
    endpoint: routeUrl("/api/tts"),
    healthEndpoint: routeUrl("/api/tts/health"),
    compatibilityHealthEndpoint: routeUrl("/tts/health"),
    method: "POST",
    synthesisMethod: "POST",
    playbackMethod: "GET",
    providerEndpointEnv: "RESEMBLE_SYNTH_URL",
    providerFallbackEndpointEnv: "RESEMBLE_STREAM_URL",
    transportModeEnv: "SB_TTS_TRANSPORT",
    transportMode: getNyxTtsRuntimeConfigStatus().transportMode,
    requiresToken: !!(CFG.requireVoiceRouteToken && CFG.apiToken),
    preserveMixerVoice: !!CFG.preserveMixerVoice,
    jsonAudioSupported: true,
    streamAudioSupported: true,
    contractVersion: "audio-first-v2",
    responseMode: "audio",
    accept: "audio/mpeg, audio/wav;q=0.9, */*;q=0.1",
    jsonAudioOptInRequired: true,
    serverLockedVoice: true,
    clientVoiceOverrideAllowed: false,
    deterministicAudio: true,
    failOpenChat: true,
    traceHeader: "x-sb-trace-id"
  };

  if (routeEnabled && shaped.reply && !shaped.audio) {
    shaped.voiceRoute = { ...route, ...existing };
  } else if (existing && Object.keys(existing).length) {
    shaped.voiceRoute = { ...route, ...existing };
  }

  return shaped;
}

function normalizeVoiceRouteResponse(out) {
  if (!isObj(out)) return null;
  const textSpeak = cleanReplyForUser(out.textSpeak || out.spokenText || out.text || out.textDisplay || "");
  const textDisplay = cleanReplyForUser(out.textDisplay || out.displayReply || out.text || textSpeak || "");
  const text = cleanReplyForUser(out.text || textDisplay || textSpeak || "");
  return {
    enabled: out.enabled !== false,
    endpoint: cleanText(out.endpoint || "/api/tts") || "/api/tts",
    healthEndpoint: cleanText(out.healthEndpoint || "/api/tts/health") || "/api/tts/health",
    compatibilityHealthEndpoint: cleanText(out.compatibilityHealthEndpoint || "/tts/health") || "/tts/health",
    method: cleanText(out.method || "POST") || "POST",
    synthesisMethod: cleanText(out.synthesisMethod || "POST") || "POST",
    playbackMethod: cleanText(out.playbackMethod || "GET") || "GET",
    providerEndpointEnv: cleanText(out.providerEndpointEnv || "RESEMBLE_SYNTH_URL") || "RESEMBLE_SYNTH_URL",
    providerFallbackEndpointEnv: cleanText(out.providerFallbackEndpointEnv || "RESEMBLE_STREAM_URL") || "RESEMBLE_STREAM_URL",
    transportModeEnv: cleanText(out.transportModeEnv || "SB_TTS_TRANSPORT") || "SB_TTS_TRANSPORT",
    transportMode: cleanText(out.transportMode || getNyxTtsRuntimeConfigStatus().transportMode || "compat-first") || "compat-first",
    requiresToken: !!out.requiresToken,
    preserveMixerVoice: !!out.preserveMixerVoice,
    jsonAudioSupported: out.jsonAudioSupported !== false,
    streamAudioSupported: out.streamAudioSupported !== false,
    contractVersion: cleanText(out.contractVersion || "audio-first-v2") || "audio-first-v2",
    responseMode: cleanText(out.responseMode || "audio") || "audio",
    accept: cleanText(out.accept || "audio/mpeg, audio/wav;q=0.9, */*;q=0.1") || "audio/mpeg, audio/wav;q=0.9, */*;q=0.1",
    jsonAudioOptInRequired: out.jsonAudioOptInRequired !== false,
    serverLockedVoice: out.serverLockedVoice !== false,
    clientVoiceOverrideAllowed: out.clientVoiceOverrideAllowed === true,
    deterministicAudio: out.deterministicAudio !== false,
    failOpenChat: out.failOpenChat !== false,
    traceHeader: cleanText(out.traceHeader || "x-sb-trace-id") || "x-sb-trace-id",
    text,
    textDisplay: textDisplay || text,
    displayReply: textDisplay || text,
    textSpeak: textSpeak || textDisplay || text,
    spokenText: textSpeak || textDisplay || text,
    routeKind: cleanText(out.routeKind || "main") || "main",
    intro: out.intro === true,
    source: cleanText(out.source || "chat") || "chat",
    speechHints: isObj(out.speechHints) ? out.speechHints : {},
    presenceProfile: cleanText(out.presenceProfile || "") || undefined,
    voiceStyle: cleanText(out.voiceStyle || "") || undefined,
    nyxStateHint: cleanText(out.nyxStateHint || "") || undefined
  };
}

function buildSpeechContract(shaped, norm) {
  const payload = isObj(shaped && shaped.payload) ? shaped.payload : {};
  const voiceRoute = isObj(shaped && shaped.voiceRoute) ? shaped.voiceRoute : {};
  const incomingSpeech = isObj(shaped && shaped.speech) ? shaped.speech : (isObj(payload.speech) ? payload.speech : {});
  const reply = cleanReplyForUser(
    (incomingSpeech.displayText || incomingSpeech.text || shaped && shaped.reply || payload.reply || payload.text || voiceRoute.text || norm && norm.text || "")
  );
  const textDisplay = cleanReplyForUser(
    incomingSpeech.displayText || payload.textDisplay || voiceRoute.textDisplay || shaped && shaped.textDisplay || reply
  ) || reply;
  const textSpeak = cleanReplyForUser(
    incomingSpeech.normalizedText || incomingSpeech.text || payload.textSpeak || voiceRoute.textSpeak || shaped && shaped.textSpeak || reply
  ) || reply;
  const routeKind = cleanText(
    payload.routeKind || voiceRoute.routeKind || shaped && shaped.routeKind || (norm && norm.mode === "intro" ? "intro" : "main")
  ) || "main";
  const intro = voiceRoute.intro === true || payload.intro === true || routeKind === "intro";
  const source = cleanText(payload.source || voiceRoute.source || (intro ? "intro" : "chat"));
  const speechHints = isObj(payload.speechHints) ? payload.speechHints : (isObj(voiceRoute.speechHints) ? voiceRoute.speechHints : {});
  return {
    enabled: incomingSpeech.enabled !== false,
    speak: incomingSpeech.speak !== false,
    text: reply,
    textDisplay,
    textSpeak,
    routeKind,
    intro,
    source: source || (intro ? "intro" : "chat"),
    speechHints,
    presenceProfile: cleanText(incomingSpeech.presenceProfile || payload.presenceProfile || "") || undefined,
    voiceStyle: cleanText(incomingSpeech.voiceStyle || payload.voiceStyle || "") || undefined,
    nyxStateHint: cleanText(incomingSpeech.nyxStateHint || payload.nyxStateHint || "") || undefined,
    alignmentVersion: "speech-contract-v2"
  };
}


function normalizeImageLike(entry, title) {
  if (!entry) return null;
  if (typeof entry === "string") {
    const url = cleanText(entry);
    return url ? { url, alt: cleanText(title || ""), caption: "" } : null;
  }
  if (!isObj(entry)) return null;
  const url = cleanText(entry.url || entry.src || entry.href || entry.image || entry.original || entry.large || entry.medium || entry.small || entry.thumbnail || "");
  if (!url) return null;
  return {
    url,
    alt: cleanText(entry.alt || entry.title || title || ""),
    caption: cleanText(entry.caption || entry.description || "")
  };
}


